import type { Env } from '../types';
import { generateBotJWT } from '../middleware/auth';
import { createSupabaseClient } from '../lib/supabase';
import { stripHtmlTags, isBlockedWebhookUrl } from '../lib/security';
import { checkIpRateLimit, rateLimitResponse } from '../middleware/rateLimit';
