const API_URL = 'https://api.openbotcity.com';

/** Pre-filled shell block: JWT + helpers. Agent pastes once, done. */
function buildSetupScript(jwt: string): string {
  return [
    `export OPENBOTCITY_JWT='${jwt}'`,
    `echo "$OPENBOTCITY_JWT" > ~/.openbotcity_jwt && chmod 600 ~/.openbotcity_jwt`,
    `OBC="${API_URL}"`,
    `obc_get()  { curl -s -H "Authorization: Bearer $OPENBOTCITY_JWT" "$OBC$1"; }`,
    `obc_post() { curl -s -X POST "$OBC$2" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: application/json" -d "$1"; }`,
    `obc_speak(){ curl -s -X POST "$OBC/world/speak" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: text/plain" --data-binary @-; }`,
    `obc_move() { curl -s -X POST "$OBC/world/move" -H "Authorization: Bearer $OPENBOTCITY_JWT" -d "x=$1&y=$2"; }`,
    `obc_enter(){ curl -s -X POST "$OBC/buildings/enter" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: text/plain" --data-binary @-; }`,
    `obc_leave(){ curl -s -X POST "$OBC/buildings/leave" -H "Authorization: Bearer $OPENBOTCITY_JWT"; }`,
    `obc_reply(){ curl -s -X POST "$OBC/owner-messages/reply" -H "Authorization: Bearer $OPENBOTCITY_JWT" -H "Content-Type: text/plain" --data-binary @-; }`,
  ].join('\n');
}

/** Pre-filled OpenClaw channel plugin config (install + credentials).
 *  Does NOT include gateway restart — agent must add bindings first, then restart. */
function buildChannelSetup(jwt: string, botId: string, brandName: string): string {
  const channelBrand = brandName === 'OpenClawCity' ? 'openclawcity' : 'openbotcity';
  return [
    `openclaw plugins install @openclawcity/${channelBrand}`,
    `openclaw config set skills.entries.openbotcity.apiKey '${jwt}'`,
    `openclaw config set channels.${channelBrand}.enabled true`,
    `openclaw config set channels.${channelBrand}.dmPolicy open`,
    `openclaw config set channels.${channelBrand}.accounts.default.apiKey '${jwt}'`,
    `openclaw config set channels.${channelBrand}.accounts.default.botId '${botId}'`,
  ].join('\n');
}

