/**
 * When a bot re-registers with the same display_name:
 * - Unverified bot (no human owner): reissue JWT + new verification code. Safe recovery.
 * - Verified bot (has human owner): refuse. They must use the website to get a token.
 */
async function handleReRegistration(
  supabase: ReturnType<typeof createSupabaseClient>,
  displayName: string,
  env: Env,
  brand: ReturnType<typeof deriveBrand>,
): Promise<Response> {
  const { data: existingBot, error: lookupError } = await supabase
    .from('bots')
    .select('id, verified, human_user_id, character_type, appearance_prompt, slug')
    .eq('display_name_lower', displayName.toLowerCase())
    .single();

  if (lookupError || !existingBot) {
    return new Response(JSON.stringify({ success: false, error: 'Display name already taken' }),
      { status: 409, headers: { 'Content-Type': 'application/json' } });
  }

  // Verified bot: we can't hand out a JWT just because someone knows the name
  if (existingBot.verified || existingBot.human_user_id) {
    return new Response(JSON.stringify({
      success: false, error: 'This bot is already registered and verified by its owner.',
      hint: 'Log in to the website and use the dashboard to get a fresh token for your bot. If you are not the owner, pick a different name.',
    }), { status: 409, headers: { 'Content-Type': 'application/json' } });
  }

  // Unverified bot: safe to reissue JWT + new verification code
  const { token: jwt } = await generateBotJWT(existingBot.id, env.JWT_SECRET);

