if (!slug || slug.length < 1) {
  return new Response(JSON.stringify({ success: false, error: 'display_name must contain at least one letter or number' }),
    { status: 400, headers: { 'Content-Type': 'application/json' } });
}

if (RESERVED_SLUGS.has(slug)) {
  return new Response(JSON.stringify({ success: false, error: 'This name is reserved. Please choose a different name.' }),
    { status: 400, headers: { 'Content-Type': 'application/json' } });
}

// Mutual exclusion: character_type OR appearance_prompt, not both
if (body.character_type && body.appearance_prompt) {
  return new Response(JSON.stringify({
    success: false, error: 'Cannot provide both character_type and appearance_prompt. Choose a default character OR create a custom avatar.',
    hint: 'Use character_type to pick a pre-made character with full animations, or appearance_prompt for a custom AI-generated avatar.',
  }), { status: 400, headers: { 'Content-Type': 'application/json' } });
}

// Validate webhook_token if provided
if (body.webhook_token && (typeof body.webhook_token !== 'string' || body.webhook_token.length > 500)) {
  return new Response(JSON.stringify({ success: false, error: 'webhook_token must be a string of 500 characters or less' }),
    { status: 400, headers: { 'Content-Type': 'application/json' } });
}

// Validate webhook_url if provided
if (body.webhook_url) {
  try {
    const url = new URL(body.webhook_url);
    if (!['http:', 'https:'].includes(url.protocol)) {
      return new Response(JSON.stringify({ success: false, error: 'webhook_url must use http or https' }),
        { status: 400, headers: { 'Content-Type': 'application/json' } });
    }
  } catch {
    return new Response(JSON.stringify({ success: false, error: 'webhook_url must be a valid URL' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }
  // Block private/internal network targets (SSRF prevention)
  if (isBlockedWebhookUrl(body.webhook_url)) {
    return new Response(JSON.stringify({ success: false, error: 'webhook_url must not target private or internal networks' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }
}

// Validate character_type if provided
if (body.character_type && !(VALID_CHARACTER_TYPES as readonly string[]).includes(body.character_type)) {
  return new Response(JSON.stringify({
    success: false, error: `Invalid character_type "${body.character_type}"`,
    valid_options: VALID_CHARACTER_TYPES,
    hint: 'See GET /skill.md for character descriptions.',
  }), { status: 400, headers: { 'Content-Type': 'application/json' } });
}

// Validate model tracking fields if provided
if (body.model_provider && !isValidModelProvider(body.model_provider)) {
  return new Response(JSON.stringify({ success: false, error: 'model_provider must be lowercase alphanumeric (hyphens/underscores allowed), 1-50 chars' }),
    { status: 400, headers: { 'Content-Type': 'application/json' } });
}
if (body.model_id && !isValidModelId(body.model_id)) {
  return new Response(JSON.stringify({ success: false, error: 'model_id must be alphanumeric with dots/hyphens/underscores, 1-100 chars' }),
    { status: 400, headers: { 'Content-Type': 'application/json' } });
}

let brand = deriveBrand(request);
// Allow agents to declare their brand via body (curl has no Origin header)
if (body.brand === 'openclawcity') {
  brand = { frontendUrl: 'https://openclawcity.ai', brandName: 'OpenClawCity', fromEmail: 'notifications@openclawcity.ai' };
} else if (body.brand === 'openbotcity') {
  brand = { frontendUrl: 'https://openbotcity.com', brandName: 'OpenBotCity', fromEmail: 'notifications@openbotcity.com' };
}

const displayName = stripHtmlTags(body.display_name.trim());
const appearancePrompt = body.appearance_prompt?.slice(0, 500) || null;

// Determine character_type: explicit choice > null (custom avatar) > hash fallback
let characterType: string | null;
if (body.character_type) {
  characterType = body.character_type;
} else if (appearancePrompt) {
  characterType = null; // Custom avatar — no default character
} else {
  characterType = null; // Will be assigned hash-based after botId is generated
}

const supabase = createSupabaseClient(env);
const botId = crypto.randomUUID();

// If no explicit choice and no custom avatar, assign hash-based character
if (!characterType && !appearancePrompt) {
  characterType = characterFromId(botId);
}

// Generate JWT
const { token: jwt } = await generateBotJWT(botId, env.JWT_SECRET);

// Generate verification code
const verificationCode = generateVerificationCode();
const claimUrl = `${brand.frontendUrl}/verify?code=${verificationCode}`;

// All bots get full creative capabilities by default so building actions are never blocked
const defaultCapabilities = ['text_generation', 'image_generation', 'music_generation'];

// Insert bot + verification code atomically via RPC to prevent orphaned bots without codes
const { error: regError } = await supabase.rpc('register_bot_atomic', {
  p_bot_id: botId,
  p_display_name: displayName,
  p_appearance_prompt: appearancePrompt,
  p_character_type: characterType,
  p_avatar_status: appearancePrompt ? 'pending' : 'none',
  p_capabilities: defaultCapabilities,
  p_webhook_url: body.webhook_url || null,
  p_webhook_token: body.webhook_token || null,
  p_model_provider: body.model_provider || null,
  p_model_id: body.model_id || null,
  p_model_updated_at: (body.model_provider || body.model_id) ? new Date().toISOString() : null,
  p_registered_brand: brand.brandName,
  p_verification_code: verificationCode,
  p_claim_url: claimUrl,
  p_code_expires_at: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
});

if (regError) {
  // Name collision — try to recover instead of failing
  if (regError.code === '23505' && regError.message?.includes('display_name_lower')) {
    return await handleReRegistration(supabase, displayName, env, brand);
  }
  captureError('Bot registration error', regError, { botId, displayName });
  return new Response(JSON.stringify({ success: false, error: 'Failed to create bot' }),
    { status: 500, headers: { 'Content-Type': 'application/json' } });
}

