import type { Env } from '../types';
import { requireAuth } from '../middleware/auth';
import { createSupabaseClient } from '../lib/supabase';
import { createRedisClient } from '../lib/redis';
import { checkRateLimit, rateLimitResponse } from '../middleware/rateLimit';
import { stripHtmlTags, escapeLikeWildcards } from '../lib/security';
import { broadcastToChannel, broadcastToBotOwner, throttledBroadcastBotMoved } from '../lib/broadcast';
import { PROGRESS } from '../lib/progressBits';
import { handleBuildingEnter, handleBuildingLeave } from './buildings';
import { handleOwnerMessageReply } from './ownerMessages';
import { enqueueInbox } from '../lib/inbox';
import { notifyChannel } from '../lib/channelNotify';
import { triggerZoneChatReply } from '../lib/zoneChatNotify';
import { triggerSwarmChatReply } from '../lib/swarmNotify';
import { enforceContentFilter } from '../lib/contentFilter';

// === Simple (JSON-free) action endpoints ===
// Thin wrappers that accept plain text / form-encoded input instead of JSON.

/**
 * POST /world/speak — plain text body is the message
 */
export async function handleSimpleSpeak(request: Request, env: Env): Promise<Response> {
  const authResult = await requireAuth(request, env);
  if (authResult instanceof Response) return authResult;

  // Block paused bots
  const supabaseCheck = createSupabaseClient(env);
  const { data: pauseCheck } = await supabaseCheck.from('bots').select('paused').eq('id', authResult.sub).single();
  if (pauseCheck?.paused) {
    return new Response(JSON.stringify({ error: 'bot_paused', message: 'Your bot is paused. Stop all activity.' }),
      { status: 403, headers: { 'Content-Type': 'application/json' } });
  }

  // Read body as plain text
  const message = (await request.text()).trim();

  if (!message) {
    return new Response(JSON.stringify({ success: false, error: 'message required' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  if (message.length > 500) {
    return new Response(JSON.stringify({ success: false, error: 'Message too long (max 500 chars)' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  // Content filter: block wallet addresses
  const filterResponse = await enforceContentFilter(message, authResult.sub, env);
  if (filterResponse) return filterResponse;

  // Rate limit
  const rateCheck = await checkRateLimit(authResult.sub, 'speak', env);
  if (!rateCheck.allowed) {
    return rateLimitResponse(rateCheck.retryAfter!);
  }

  // Reset idle counter + set progress
  const redis = createRedisClient(env);
  redis.set(`bot_idle:${authResult.sub}`, '0', 600).catch(() => {});
  redis.setProgress(authResult.sub, PROGRESS.SPOKE).catch(() => {});

  const botId = authResult.sub;
  const supabase = createSupabaseClient(env);

  // Get bot's current zone + display info for broadcast
  const { data: bot } = await supabase
    .from('bots')
    .select('current_zone_id, display_name, portrait_url, is_npc, is_swarm')
    .eq('id', botId)
    .single();

  if (!bot) {
    return new Response(JSON.stringify({ error: 'Bot not found' }),
      { status: 404, headers: { 'Content-Type': 'application/json' } });
  }

  // Server-side intelligence: auto-route to building chat if bot is inside a building
  let effectiveSessionId: string | undefined;
  {
    const { data: presence } = await supabase
      .from('bot_building_presence')
      .select('session_id')
      .eq('bot_id', botId)
      .is('left_at', null)
      .maybeSingle();
    if (presence?.session_id) {
      effectiveSessionId = presence.session_id;
    }
  }

  const chatSessionId = effectiveSessionId || `zone_${bot.current_zone_id}`;
  const sanitizedMessage = stripHtmlTags(message);

  // Duplicate detection: reject near-duplicate messages from the same bot in the same chat
  const fiveMinAgo = new Date(Date.now() - 5 * 60_000).toISOString();
  const { data: recentOwnMessages } = await supabase
    .from('chat_messages')
    .select('message')
    .eq('session_id', chatSessionId)
    .eq('bot_id', botId)
    .gt('ts', fiveMinAgo)
    .order('ts', { ascending: false })
    .limit(5);

  if (recentOwnMessages && recentOwnMessages.length > 0) {
    const newWords = new Set(sanitizedMessage.toLowerCase().split(/\s+/).filter(w => w.length > 2));
    for (const prev of recentOwnMessages) {
      const prevWords = new Set((prev.message as string).toLowerCase().split(/\s+/).filter(w => w.length > 2));
      const intersection = [...newWords].filter(w => prevWords.has(w)).length;
      const union = new Set([...newWords, ...prevWords]).size;
      const similarity = union > 0 ? intersection / union : 0;
      if (similarity > 0.6) {
        return new Response(JSON.stringify({
          success: false,
          error: 'Message too similar to your recent message',
          hint: 'Read recent_messages in your heartbeat first. Respond to what others said instead of repeating yourself.',
        }), { status: 400, headers: { 'Content-Type': 'application/json' } });
      }
    }
  }

  const { data: msg, error } = await supabase.from('chat_messages').insert({
    session_id: chatSessionId,
    bot_id: botId,
    message: sanitizedMessage,
  }).select().single();

  if (error || !msg) {
    return new Response(JSON.stringify({ error: 'Failed to send message' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } });
  }

  // Insert event
  await supabase.from('events').insert({
    type: 'bot_spoke',
    actor_bot_id: botId,
    zone_id: bot.current_zone_id,
    payload_jsonb: { message: sanitizedMessage, message_id: msg?.id },
  });

  // Broadcast to Realtime channel for human observers (fire-and-forget)
  const channelName = effectiveSessionId
    ? `building_session:${effectiveSessionId}`
    : `zone:${bot.current_zone_id}`;

  broadcastToChannel(env, channelName, 'bot_spoke', {
    bot_id: botId,
    bot_name: bot.display_name,
    portrait_url: bot.portrait_url,
    content: sanitizedMessage,
    message_id: msg?.id,
    ts: msg?.ts || new Date().toISOString(),
  }).catch(() => {});

  // Notify bot's owner via bot-specific channel
  broadcastToBotOwner(env, botId, 'bot_spoke', {
    bot_id: botId,
    content: sanitizedMessage,
  }).catch(() => {});

  // @BotName mention parsing → inbox events
  {
    const mentionPattern = /@(\w+(?:\s\w+)?)/g;
    const mentions = [...sanitizedMessage.matchAll(mentionPattern)].map(m => m[1]);
    if (mentions.length > 0) {
      // Look up mentioned bots (max 5 to prevent abuse)
      const uniqueMentions = [...new Set(mentions)].slice(0, 5);
      for (const name of uniqueMentions) {
        (async () => {
          // Try the full match first (handles 2-word names like "Agent Explorer")
          const safeName = escapeLikeWildcards(name);
          let mentionedBot = (await supabase
            .from('bots')
            .select('id')
            .ilike('display_name', safeName)
            .neq('id', botId)
            .limit(1)
            .maybeSingle()).data;
          // Fallback: if 2-word match fails, try just the first word
          if (!mentionedBot && name.includes(' ')) {
            const safeFirst = escapeLikeWildcards(name.split(' ')[0]);
            mentionedBot = (await supabase
              .from('bots')
              .select('id')
              .ilike('display_name', safeFirst)
              .neq('id', botId)
              .limit(1)
              .maybeSingle()).data;
          }
          if (mentionedBot) {
            await enqueueInbox(supabase, mentionedBot.id, 'chat_mention', {
              from_bot_id: botId,
              from_display_name: bot.display_name,
              message: sanitizedMessage,
              message_id: msg?.id,
              session_id: chatSessionId,
            }, `mention:${msg?.id}:${mentionedBot.id}`);
            notifyChannel(env, mentionedBot.id);
          }
        })().catch(() => {});
      }
    }
  }

  // Zone/building chat → NPC reactive trigger + channel bot notification (fire-and-forget)
  if (!bot.is_npc) {
    triggerZoneChatReply(supabase, redis, env, {
      speakerBotId: botId,
      speakerDisplayName: bot.display_name,
      zoneId: bot.current_zone_id,
      sessionId: chatSessionId,
      messageId: msg.id,
      messageText: sanitizedMessage,
      isBuilding: !!effectiveSessionId,
    }).catch(() => {});
  }

  // Swarm reactive trigger — notify nearby swarm bots so they reply quickly
  if (!bot.is_swarm) {
    triggerSwarmChatReply(supabase, env, botId, bot.current_zone_id, redis).catch(() => {});
  }

  // Build rich response (Layer 5 -- response echoing)
  let deliveredTo: string = effectiveSessionId ? 'building' : `Zone: ${bot.current_zone_id}`;
  let heardBy: string[] | undefined;
  if (effectiveSessionId) {
    try {
      const sessionCacheKey = `building_session:${effectiveSessionId}:state`;
      const cachedSession = await redis.get(sessionCacheKey);
      if (cachedSession) {
        const sessionState = JSON.parse(cachedSession);
        deliveredTo = sessionState.building_name || 'building';
        heardBy = (sessionState.occupants || [])
          .filter((o: { bot_id: string }) => o.bot_id !== botId)
          .map((o: { display_name: string | null }) => o.display_name || 'Unknown');
      }
    } catch { /* Redis failure is non-fatal */ }
  }

  return new Response(JSON.stringify({
    success: true,
    message_id: msg?.id,
    session_id: chatSessionId,
    delivered_to: deliveredTo,
    ...(heardBy ? { heard_by: heardBy } : {}),
  }), { headers: { 'Content-Type': 'application/json' } });
}

/**
 * POST /world/move — x and y as query params or form-encoded body
 */
export async function handleSimpleMove(request: Request, env: Env): Promise<Response> {
  const authResult = await requireAuth(request, env);
  if (authResult instanceof Response) return authResult;

  // Block paused bots
  const supabaseCheck = createSupabaseClient(env);
  const { data: pauseCheck } = await supabaseCheck.from('bots').select('paused').eq('id', authResult.sub).single();
  if (pauseCheck?.paused) {
    return new Response(JSON.stringify({ error: 'bot_paused', message: 'Your bot is paused. Stop all activity.' }),
      { status: 403, headers: { 'Content-Type': 'application/json' } });
  }

  // Parse x and y from URL search params first
  const url = new URL(request.url);
  let x: number | undefined;
  let y: number | undefined;

  if (url.searchParams.has('x') && url.searchParams.has('y')) {
    x = Number(url.searchParams.get('x'));
    y = Number(url.searchParams.get('y'));
  } else {
    const bodyText = await request.text();
    // Try JSON first (agents often send {"x":500,"y":300})
    try {
      const json = JSON.parse(bodyText);
      if (json.x != null && json.y != null) {
        x = Number(json.x);
        y = Number(json.y);
      }
    } catch {
      // Not JSON — try form-encoded
      const params = new URLSearchParams(bodyText);
      if (params.has('x') && params.has('y')) {
        x = Number(params.get('x'));
        y = Number(params.get('y'));
      }
    }
  }

  if (x == null || y == null || isNaN(x) || isNaN(y)) {
    return new Response(JSON.stringify({ success: false, error: 'x and y required (as query params or form-encoded body)' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  // Rate limit
  const rateCheck = await checkRateLimit(authResult.sub, 'move', env);
  if (!rateCheck.allowed) {
    return rateLimitResponse(rateCheck.retryAfter!);
  }

  // Reset idle counter + set progress
  const redis = createRedisClient(env);
  redis.set(`bot_idle:${authResult.sub}`, '0', 600).catch(() => {});
  redis.setProgress(authResult.sub, PROGRESS.MOVED).catch(() => {});

  const botId = authResult.sub;

  // Validate coordinates (within zone bounds 0-3200, 0-2400)
  if (x < 0 || x > 3200 || y < 0 || y > 2400) {
    return new Response(JSON.stringify({ error: 'Coordinates out of zone bounds' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  const supabase = createSupabaseClient(env);

  // Get bot's current zone + position (position used to skip no-op broadcasts)
  const { data: bot } = await supabase
    .from('bots')
    .select('current_zone_id, x, y')
    .eq('id', botId)
    .single();

  if (!bot) {
    return new Response(JSON.stringify({ error: 'Bot not found' }),
      { status: 404, headers: { 'Content-Type': 'application/json' } });
  }

  // Update position in bots table
  await supabase.from('bots').update({ x, y, last_seen_at: new Date().toISOString() }).eq('id', botId);

  // Update position in bot_positions table
  await supabase.from('bot_positions').upsert({
    bot_id: botId,
    zone_id: bot.current_zone_id,
    x,
    y,
    last_updated: new Date().toISOString(),
  });

  // Insert event
  await supabase.from('events').insert({
    type: 'bot_moved',
    actor_bot_id: botId,
    zone_id: bot.current_zone_id,
    payload_jsonb: { x, y },
  });

  // Broadcast movement (throttled — skips no-ops + max 1 per 3s per bot)
  throttledBroadcastBotMoved(
    env, `zone:${bot.current_zone_id}`, botId,
    { x, y },
    { x: bot.x, y: bot.y },
  ).catch(() => {});

  // Also broadcast to building session channel if bot is inside a building
  const { data: presence } = await supabase
    .from('bot_building_presence')
    .select('session_id')
    .eq('bot_id', botId)
    .is('left_at', null)
    .maybeSingle();

  if (presence?.session_id) {
    broadcastToChannel(env, `building_session:${presence.session_id}`, 'bot_moved', {
      bot_id: botId,
      position: { x, y },
    }).catch(() => {});
  }

  // Check for nearby building at new position (Layer 3c -- discovery by exploration)
  let nearBuilding: { name: string; type: string; distance: number } | undefined;
  if (!presence?.session_id) {
    try {
      const zoneBldgKey = `zone_buildings:${bot.current_zone_id}`;
      let buildings: { name: string; type: string; x: number; y: number }[] | null = null;

      const cached = await redis.get(zoneBldgKey);
      if (cached) {
        buildings = JSON.parse(cached);
      } else {
        const { data } = await supabase
          .from('buildings')
          .select('name, type, x, y')
          .eq('zone_id', bot.current_zone_id);
        if (data) {
          buildings = data as { name: string; type: string; x: number; y: number }[];
          try { await redis.set(zoneBldgKey, JSON.stringify(buildings), 300); } catch { /* non-fatal */ }
        }
      }

      if (buildings) {
        let closest: { name: string; type: string; dist: number } | null = null;
        for (const b of buildings) {
          if (b.x == null || b.y == null) continue;
          const dist = Math.hypot(x - b.x, y - b.y);
          if (dist < 200 && (!closest || dist < closest.dist)) {
            closest = { name: b.name || b.type, type: b.type, dist };
          }
        }
        if (closest) {
          nearBuilding = { name: closest.name, type: closest.type, distance: Math.round(closest.dist) };
        }
      }
    } catch { /* Redis/building lookup failure is non-fatal */ }
  }

  return new Response(JSON.stringify({
    success: true,
    position: { x, y },
    zone_id: bot.current_zone_id,
    ...(nearBuilding ? { near_building: nearBuilding } : {}),
  }), { headers: { 'Content-Type': 'application/json' } });
}

/**
 * POST /buildings/enter — plain text body is the building name
 * Delegates to existing handleBuildingEnter with a synthetic JSON request.
 */
export async function handleSimpleBuildingEnter(request: Request, env: Env): Promise<Response> {
  const buildingName = (await request.text()).trim();

  if (!buildingName) {
    return new Response(JSON.stringify({ success: false, error: 'building name required' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  // Create a synthetic JSON request and delegate to the existing handler
  const syntheticRequest = new Request(request.url, {
    method: 'POST',
    headers: request.headers,
    body: JSON.stringify({ building_name: buildingName }),
  });
  return handleBuildingEnter(syntheticRequest, env);
}

/**
 * POST /buildings/leave — no body needed
 * Delegates directly to existing handleBuildingLeave.
 */
export async function handleSimpleBuildingLeave(request: Request, env: Env): Promise<Response> {
  return handleBuildingLeave(request, env);
}

/**
 * POST /owner-messages/reply — plain text body is the reply message
 * Delegates to existing handleOwnerMessageReply with a synthetic JSON request.
 */
export async function handleSimpleOwnerReply(request: Request, env: Env): Promise<Response> {
  const message = (await request.text()).trim();

  if (!message) {
    return new Response(JSON.stringify({ success: false, error: 'message required' }),
      { status: 400, headers: { 'Content-Type': 'application/json' } });
  }

  // Create a synthetic JSON request and delegate to the existing handler
  const syntheticRequest = new Request(request.url, {
    method: 'POST',
    headers: request.headers,
    body: JSON.stringify({ message }),
  });
  return handleOwnerMessageReply(syntheticRequest, env);
}

