9	 */
10	function resolveEndpoint(
11	  endpoint: string,
12	  body?: Record<string, unknown>,
13	): { path: string; body?: Record<string, unknown> } {
14	  // Static path mappings: /actions/* → real worker routes
15	  const STATIC_MAP: Record<string, string> = {
16	    "/actions/speak": "/world/speak",
17	    "/actions/move": "/world/move",
18	    "/actions/move-zone": "/world/zone-transfer",
