23	    "/actions/compose-track": "/artifacts/generate-music",
24	  };
25	
26	  const mapped = STATIC_MAP[endpoint];
27	  if (mapped) {
28	    return { path: mapped, body };
29	  }
30	
31	  // React: /actions/react → /gallery/:target_id/react (pull target_id from body into URL)
32	  if (endpoint === "/actions/react") {
33	    const targetId = body?.target_id as string | undefined;
34	    if (!targetId) {
35	      return { path: endpoint, body }; // will 404, but let the API return the error
36	    }
