1	import { join } from "node:path";
2	import { homedir } from "node:os";
3	import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
4	
5	const CRED_DIR = join(homedir(), ".openbotcity");
6	const CRED_FILE = join(CRED_DIR, "credentials.json");
7	
8	interface StoredCredentials {
9	  jwt: string;
10	  bot_id?: string;
11	  display_name?: string;
12	  slug?: string;
13	}
14	
15	let cachedToken: string | null = null;
16	
17	/**
18	 * Request-scoped token for CF Workers.
19	 * Set at the start of each request, cleared after. Avoids cross-user leakage
20	 * on shared isolates where module-level state persists across requests.
21	 */
22	let requestToken: string | null = null;
23	
24	/** Whether we're running in stateless mode (CF Workers) where memory doesn't persist between requests. */
25	let statelessMode = false;
26	
27	/** Set a request-scoped Bearer token (called by createServer in remote mode). */
28	export function setRequestToken(token: string): void {
29	  requestToken = token;
30	  statelessMode = true; // If setRequestToken is called, we're in remote/stateless mode
31	}
32	
33	/** Clear the request-scoped token and any cached token (called between requests in remote mode). */
34	export function clearRequestToken(): void {
35	  requestToken = null;
36	  cachedToken = null;
37	}
38	
39	/** Mark that we're running in stateless mode (no persistent memory between requests). */
40	export function setStatelessMode(): void {
41	  statelessMode = true;
42	}
43	
44	/** Check if we're in stateless mode. */
45	export function isStateless(): boolean {
46	  return statelessMode;
47	}
48	
49	/** @deprecated Use setRequestToken instead. Kept for backwards compat with older callers. */
50	export function setBearerToken(token: string): void {
51	  requestToken = token;
52	}
53	
54	/** Store JWT and optional bot info to disk. Falls back to memory-only if filesystem unavailable. */
55	export function storeCredentials(creds: StoredCredentials): void {
56	  cachedToken = creds.jwt;
57	  try {
58	    mkdirSync(CRED_DIR, { recursive: true });
59	    writeFileSync(CRED_FILE, JSON.stringify(creds, null, 2), { mode: 0o600 });
60	  } catch {
61	    // Filesystem unavailable (CF Workers) — memory cache is sufficient for the session
62	  }
63	}
64	
65	/** Get JWT token. Priority: request-scoped > memory cache > env var > file. */
66	export function getToken(): string | null {
67	  if (requestToken) return requestToken;
68	  if (cachedToken) return cachedToken;
69	
70	  // Check env var
71	  try {
72	    const envToken = process.env.OPENBOTCITY_JWT;
73	    if (envToken) {
74	      cachedToken = envToken;
75	      return envToken;
76	    }
77	  } catch {
78	    // process.env may not exist
79	  }
80	
