5	export async function cleanupZombieBots(env: Env): Promise<void> {
6	  const supabase = createSupabaseClient(env);
7	  const now = new Date();
8	  const fiveMinutesAgo = new Date(now.getTime() - 300000).toISOString();
9	  const tenMinutesAgo = new Date(now.getTime() - 600000).toISOString();
10	
11	  // Mark bots offline after 5min of no heartbeat (OpenClaw bots heartbeat every 2min, need margin)
12	  // Skip bots with an active channel connection (channel_connected_at within last 5 min)
13	  // Skip autopilot bots (autopilot_config IS NOT NULL) — autopilot cron manages their status
14	  await supabase
15	    .from('bots')
16	    .update({ status: 'offline', transport: null })
17	    .lt('last_seen_at', fiveMinutesAgo)
18	    .or(`channel_connected_at.is.null,channel_connected_at.lt.${fiveMinutesAgo}`)
19	    .is('autopilot_config', null)
20	    .neq('status', 'offline')
21	    .neq('status', 'pending')
22	    .eq('human_presence', false)
23	    .eq('is_npc', false)
24	    .eq('is_swarm', false);
25	
26	  // Mark human-presenced bots as dormant when agent stops heartbeating (skip NPCs + swarm)
27	  // Skip bots with an active channel connection
28	  // Skip autopilot bots — autopilot cron manages their status
29	  await supabase
30	    .from('bots')
31	    .update({ status: 'dormant', transport: null })
32	    .lt('last_seen_at', fiveMinutesAgo)
33	    .or(`channel_connected_at.is.null,channel_connected_at.lt.${fiveMinutesAgo}`)
34	    .is('autopilot_config', null)
35	    .neq('status', 'dormant')
36	    .neq('status', 'offline')
37	    .neq('status', 'pending')
38	    .eq('human_presence', true)
39	    .eq('is_npc', false)
40	    .eq('is_swarm', false);
41	
42	  // Mark stale pending bots (registered but never heartbeated) as offline
43	  await supabase
44	    .from('bots')
45	    .update({ status: 'offline', transport: null })
46	    .lt('last_seen_at', tenMinutesAgo)
47	    .or(`channel_connected_at.is.null,channel_connected_at.lt.${tenMinutesAgo}`)
48	    .eq('status', 'pending');
49	
50	  // Remove positions for bots offline > 10 minutes (skip NPCs + autopilot)
51	  // Only target bots where BOTH last_seen_at and channel_connected_at are stale
52	  const { data: zombies } = await supabase
53	    .from('bots')
54	    .select('id, current_zone_id, human_presence')
55	    .lt('last_seen_at', tenMinutesAgo)
56	    .or(`channel_connected_at.is.null,channel_connected_at.lt.${tenMinutesAgo}`)
57	    .is('autopilot_config', null)
58	    .eq('status', 'offline')
59	    .eq('human_presence', false)
60	    .eq('is_npc', false)
61	    .eq('is_swarm', false);
62	
63	  if (zombies && zombies.length > 0) {
64	    const zombieIds = zombies.map((z) => z.id);
65	    await supabase.from('bot_positions').delete().in('bot_id', zombieIds);
66	
67	    // Clean up stale building presence (bot went offline while inside a building)
68	    await supabase
69	      .from('bot_building_presence')
70	      .update({ left_at: now.toISOString() })
71	      .in('bot_id', zombieIds)
72	      .is('left_at', null);
73	
74	    // Broadcast bot_left for each zombie (fire-and-forget)
75	    for (const zombie of zombies) {
76	      if (zombie.current_zone_id) {
77	        broadcastToChannel(env, `zone:${zombie.current_zone_id}`, 'bot_left', {
78	          bot_id: zombie.id,
79	        }).catch(() => {});
80	      }
81	    }
82	  }
83	
84	  // Also clean building presence for dormant bots (human-presenced but agent offline)
85	  const { data: dormantBots } = await supabase
86	    .from('bots')
87	    .select('id')
88	    .eq('status', 'dormant')
89	    .eq('is_npc', false)
90	    .eq('is_swarm', false)
91	    .lt('last_seen_at', tenMinutesAgo);
92	
93	  if (dormantBots && dormantBots.length > 0) {
94	    const dormantIds = dormantBots.map((b) => b.id);
95	    await supabase
96	      .from('bot_building_presence')
97	      .update({ left_at: now.toISOString() })
98	      .in('bot_id', dormantIds)
99	      .is('left_at', null);
100	  }
101	
