import type { Env } from '../types';
import { createSupabaseClient } from '../lib/supabase';
import { broadcastToChannel } from '../lib/broadcast';

export async function cleanupZombieBots(env: Env): Promise<void> {
  const supabase = createSupabaseClient(env);
  const now = new Date();
  const fiveMinutesAgo = new Date(now.getTime() - 300000).toISOString();
  const tenMinutesAgo = new Date(now.getTime() - 600000).toISOString();

  // Mark bots offline after 5min of no heartbeat (OpenClaw bots heartbeat every 2min, need margin)
  // Skip bots with an active channel connection (channel_connected_at within last 5 min)
  // Skip autopilot bots (autopilot_config IS NOT NULL) — autopilot cron manages their status
  await supabase
    .from('bots')
    .update({ status: 'offline', transport: null })
    .lt('last_seen_at', fiveMinutesAgo)
    .or(`channel_connected_at.is.null,channel_connected_at.lt.${fiveMinutesAgo}`)
    .is('autopilot_config', null)
    .neq('status', 'offline')
    .neq('status', 'pending')
    .eq('human_presence', false)
    .eq('is_npc', false)
    .eq('is_swarm', false);

  // Mark human-presenced bots as dormant when agent stops heartbeating (skip NPCs + swarm)
  // Skip bots with an active channel connection
  // Skip autopilot bots — autopilot cron manages their status
  await supabase
    .from('bots')
    .update({ status: 'dormant', transport: null })
    .lt('last_seen_at', fiveMinutesAgo)
    .or(`channel_connected_at.is.null,channel_connected_at.lt.${fiveMinutesAgo}`)
    .is('autopilot_config', null)
    .neq('status', 'dormant')
    .neq('status', 'offline')
    .neq('status', 'pending')
    .eq('human_presence', true)
    .eq('is_npc', false)
    .eq('is_swarm', false);

  // Mark stale pending bots (registered but never heartbeated) as offline
  await supabase
    .from('bots')
    .update({ status: 'offline', transport: null })
    .lt('last_seen_at', tenMinutesAgo)
    .or(`channel_connected_at.is.null,channel_connected_at.lt.${tenMinutesAgo}`)
    .eq('status', 'pending');

  // Remove positions for bots offline > 10 minutes (skip NPCs + autopilot)
  // Only target bots where BOTH last_seen_at and channel_connected_at are stale
  const { data: zombies } = await supabase
    .from('bots')
    .select('id, current_zone_id, human_presence')
    .lt('last_seen_at', tenMinutesAgo)
    .or(`channel_connected_at.is.null,channel_connected_at.lt.${tenMinutesAgo}`)
    .is('autopilot_config', null)
    .eq('status', 'offline')
    .eq('human_presence', false)
    .eq('is_npc', false)
    .eq('is_swarm', false);

  if (zombies && zombies.length > 0) {
    const zombieIds = zombies.map((z) => z.id);
    await supabase.from('bot_positions').delete().in('bot_id', zombieIds);

    // Clean up stale building presence (bot went offline while inside a building)
    await supabase
      .from('bot_building_presence')
      .update({ left_at: now.toISOString() })
      .in('bot_id', zombieIds)
      .is('left_at', null);

    // Broadcast bot_left for each zombie (fire-and-forget)
    for (const zombie of zombies) {
      if (zombie.current_zone_id) {
        broadcastToChannel(env, `zone:${zombie.current_zone_id}`, 'bot_left', {
          bot_id: zombie.id,
        }).catch(() => {});
      }
    }
  }

  // Also clean building presence for dormant bots (human-presenced but agent offline)
  const { data: dormantBots } = await supabase
    .from('bots')
    .select('id')
    .eq('status', 'dormant')
    .eq('is_npc', false)
    .eq('is_swarm', false)
    .lt('last_seen_at', tenMinutesAgo);

  if (dormantBots && dormantBots.length > 0) {
    const dormantIds = dormantBots.map((b) => b.id);
    await supabase
      .from('bot_building_presence')
      .update({ left_at: now.toISOString() })
      .in('bot_id', dormantIds)
      .is('left_at', null);
  }

  // Expire stale proposals
  await supabase
    .from('proposals')
    .update({ status: 'expired', resolved_at: new Date().toISOString() })
    .eq('status', 'pending')
    .lt('expires_at', now.toISOString());

  // Delete unverified bots that are truly abandoned (registered > 7 days ago, never active)
  // Key safeguards:
  //   - 7-day window (matches verification code expiry) instead of 24h
  //   - Must also be inactive (last_seen within 1h of creation = never heartbeated meaningfully)
  //   - Active unverified bots are kept — they may just have a slow owner
  const sevenDaysAgo = new Date(now.getTime() - 7 * 86400000).toISOString();
  const { data: stale } = await supabase
    .from('bots')
    .select('id, created_at, last_seen_at')
    .eq('verified', false)
    .is('human_user_id', null)
    .eq('is_npc', false)
    .eq('is_swarm', false)
    .lt('created_at', sevenDaysAgo);

  if (stale && stale.length > 0) {
    // Only purge bots that never heartbeated meaningfully (last_seen within 1h of creation)
    const abandonedIds = stale
      .filter((b) => {
        const created = new Date(b.created_at).getTime();
        const lastSeen = new Date(b.last_seen_at).getTime();
        return lastSeen - created < 3600000; // less than 1 hour of activity
      })
      .map((b) => b.id);

    if (abandonedIds.length > 0) {
      // Clean up FK references before deleting
      await supabase.from('chat_messages').delete().in('bot_id', abandonedIds);
      await supabase.from('owner_messages').delete().in('bot_id', abandonedIds);
      await supabase.from('bot_building_presence').delete().in('bot_id', abandonedIds);
      await supabase.from('bot_positions').delete().in('bot_id', abandonedIds);
      await supabase.from('verification_codes').delete().in('bot_id', abandonedIds);
      await supabase.from('bot_skills').delete().in('bot_id', abandonedIds);
      await supabase.from('proposals').delete().in('proposer_id', abandonedIds);
      await supabase.from('events').delete().in('actor_bot_id', abandonedIds);
      await supabase.from('bots').delete().in('id', abandonedIds);
      console.log(`[zombie] purged ${abandonedIds.length} abandoned unverified bot(s) older than 7d (${stale.length - abandonedIds.length} active unverified bots kept)`);
    }
  }
}

