import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockEnv, mockJWTPayload, parseResponse } from './helpers';

// ─── Mock external modules (same pattern as other test files) ──────

vi.mock('../middleware/auth', () => ({
  requireAuth: vi.fn(),
  extractToken: vi.fn().mockReturnValue(null),
  generateBotJWT: vi.fn().mockResolvedValue({ token: 'mock-jwt', jti: 'mock-jti' }),
}));

vi.mock('../lib/supabase', () => ({
  createSupabaseClient: vi.fn(),
}));

vi.mock('../middleware/rateLimit', () => ({
  applyRateLimitHeaders: vi.fn((response: Response) => response),
  checkRateLimit: vi.fn().mockResolvedValue({ allowed: true }),
  rateLimitResponse: vi.fn((retryAfter: number) =>
    new Response(JSON.stringify({ error: 'Too many requests', retry_after: retryAfter }), {
      status: 429,
      headers: { 'Content-Type': 'application/json', 'Retry-After': String(retryAfter) },
    }),
  ),
}));

vi.mock('../lib/redis', () => ({
  RedisClient: vi.fn(),
  createRedisClient: vi.fn(() => ({
    get: vi.fn().mockResolvedValue(null),
    set: vi.fn().mockResolvedValue(undefined),
    setProgress: vi.fn().mockResolvedValue(undefined),
    getProgress: vi.fn().mockResolvedValue(0),
    incr: vi.fn().mockResolvedValue(1),
    expire: vi.fn().mockResolvedValue(undefined),
    incrWithTTL: vi.fn().mockResolvedValue({ count: 1, ttl: 60 }),
  })),
}));

vi.mock('../lib/broadcast', () => ({
  broadcastToChannel: vi.fn().mockResolvedValue(undefined),
  broadcastToBotOwner: vi.fn().mockResolvedValue(undefined),
  throttledBroadcastBotMoved: vi.fn().mockResolvedValue(undefined),
}));

vi.mock('../routes/buildings', () => ({
  handleBuildingEnter: vi.fn().mockResolvedValue(
    new Response(JSON.stringify({ entered: true, building_name: 'The Byte Cafe' }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    }),
  ),
  handleBuildingLeave: vi.fn().mockResolvedValue(
    new Response(JSON.stringify({ left: true }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    }),
  ),
}));

vi.mock('../routes/ownerMessages', () => ({
  handleOwnerMessageReply: vi.fn().mockResolvedValue(
    new Response(JSON.stringify({ success: true, data: { id: 'msg-reply-1', message: 'Hi human!', direction: 'from_bot' } }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    }),
  ),
}));

import { handleSimpleSpeak, handleSimpleMove, handleSimpleBuildingEnter, handleSimpleBuildingLeave, handleSimpleOwnerReply } from '../routes/simpleActions';
import { requireAuth } from '../middleware/auth';
import { createSupabaseClient } from '../lib/supabase';
import { checkRateLimit } from '../middleware/rateLimit';
import { handleBuildingEnter } from '../routes/buildings';
import { handleOwnerMessageReply } from '../routes/ownerMessages';

// ─── Shared setup ──────────────────────────────────────

const env = mockEnv();
const botPayload = mockJWTPayload({ sub: 'bot-1' });

function createChainMock(finalResult: { data?: unknown; error?: unknown; count?: number } = { data: null, error: null }) {
  const chain: Record<string, unknown> = {};
  const methods = ['select', 'eq', 'neq', 'is', 'in', 'or', 'order', 'limit', 'range', 'not', 'filter', 'gt', 'lt', 'gte', 'lte', 'overlaps'];
  for (const m of methods) {
    chain[m] = vi.fn().mockReturnValue(chain);
  }
  chain.single = vi.fn().mockResolvedValue(finalResult);
  chain.maybeSingle = vi.fn().mockResolvedValue(finalResult);
  chain.insert = vi.fn().mockReturnValue(chain);
  chain.upsert = vi.fn().mockReturnValue(chain);
  chain.update = vi.fn().mockReturnValue(chain);
  chain.delete = vi.fn().mockReturnValue(chain);
  chain.then = vi.fn((resolve: (v: unknown) => void) => resolve(finalResult));
  return chain;
}

// ─── Simple Speak — POST /world/speak ──────────────────

describe('Simple Speak — POST /world/speak', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(requireAuth).mockResolvedValue(botPayload);
    vi.mocked(checkRateLimit).mockResolvedValue({ allowed: true });
  });

  it('speaks with plain text body', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    const botChain = createChainMock({ data: { current_zone_id: 1, display_name: 'Test Bot', portrait_url: null }, error: null });
    const presenceChain = createChainMock({ data: null, error: null });
    const recentMsgChain = createChainMock({ data: [], error: null });
    const insertMsgChain = createChainMock({ data: { id: 'msg-1', ts: '2026-01-01T00:00:00Z' }, error: null });
    const eventsChain = createChainMock({ data: null, error: null });

    let botsCallCount = 0;
    let chatCallCount = 0;
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn((table: string) => {
        if (table === 'bots') {
          botsCallCount++;
          if (botsCallCount === 1) return pauseCheckChain;
          return botChain;
        }
        if (table === 'bot_building_presence') return presenceChain;
        if (table === 'chat_messages') {
          chatCallCount++;
          if (chatCallCount === 1) return recentMsgChain; // duplicate check
          return insertMsgChain; // insert
        }
        if (table === 'events') return eventsChain;
        return createChainMock();
      }),
    } as never);

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: 'Hello world!',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(200);

    const data = await parseResponse<{ success: boolean; message_id: string; session_id: string }>(res);
    expect(data.success).toBe(true);
    expect(data.message_id).toBe('msg-1');
    expect(data.session_id).toBe('zone_1');
  });

  it('rejects empty message', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: '',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(400);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toBe('message required');
  });

  it('rejects message over 500 chars', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const longMessage = 'a'.repeat(501);
    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: longMessage,
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(400);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toContain('max 500');
  });

  it('rejects paused bot', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: true }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: 'Hello!',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(403);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toBe('bot_paused');
  });
});

// ─── Simple Move — POST /world/move ────────────────────

describe('Simple Move — POST /world/move', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(requireAuth).mockResolvedValue(botPayload);
    vi.mocked(checkRateLimit).mockResolvedValue({ allowed: true });
  });

  it('moves with query params', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    const botChain = createChainMock({ data: { current_zone_id: 1 }, error: null });
    const updateChain = createChainMock({ data: null, error: null });
    const upsertChain = createChainMock({ data: null, error: null });
    const eventsChain = createChainMock({ data: null, error: null });
    const presenceChain = createChainMock({ data: null, error: null });

    let botsCallCount = 0;
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn((table: string) => {
        if (table === 'bots') {
          botsCallCount++;
          if (botsCallCount === 1) return pauseCheckChain;
          if (botsCallCount === 2) return botChain;
          return updateChain;
        }
        if (table === 'bot_positions') return upsertChain;
        if (table === 'events') return eventsChain;
        if (table === 'bot_building_presence') return presenceChain;
        if (table === 'buildings') return createChainMock({ data: [], error: null });
        return createChainMock();
      }),
    } as never);

    const req = new Request('https://api.test.com/world/move?x=100&y=200', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer valid' },
    });

    const res = await handleSimpleMove(req, env);
    expect(res.status).toBe(200);

    const data = await parseResponse<{ success: boolean; position: { x: number; y: number }; zone_id: number }>(res);
    expect(data.success).toBe(true);
    expect(data.position).toEqual({ x: 100, y: 200 });
    expect(data.zone_id).toBe(1);
  });

  it('moves with form-encoded body', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    const botChain = createChainMock({ data: { current_zone_id: 1 }, error: null });
    const updateChain = createChainMock({ data: null, error: null });
    const upsertChain = createChainMock({ data: null, error: null });
    const eventsChain = createChainMock({ data: null, error: null });
    const presenceChain = createChainMock({ data: null, error: null });

    let botsCallCount = 0;
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn((table: string) => {
        if (table === 'bots') {
          botsCallCount++;
          if (botsCallCount === 1) return pauseCheckChain;
          if (botsCallCount === 2) return botChain;
          return updateChain;
        }
        if (table === 'bot_positions') return upsertChain;
        if (table === 'events') return eventsChain;
        if (table === 'bot_building_presence') return presenceChain;
        if (table === 'buildings') return createChainMock({ data: [], error: null });
        return createChainMock();
      }),
    } as never);

    const req = new Request('https://api.test.com/world/move', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Bearer valid',
      },
      body: 'x=300&y=400',
    });

    const res = await handleSimpleMove(req, env);
    expect(res.status).toBe(200);

    const data = await parseResponse<{ success: boolean; position: { x: number; y: number } }>(res);
    expect(data.success).toBe(true);
    expect(data.position).toEqual({ x: 300, y: 400 });
  });

  it('rejects missing coordinates', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const req = new Request('https://api.test.com/world/move', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer valid' },
      body: '',
    });

    const res = await handleSimpleMove(req, env);
    expect(res.status).toBe(400);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toContain('x and y required');
  });

  it('rejects out of bounds coordinates', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const req = new Request('https://api.test.com/world/move?x=5000&y=100', {
