          botsCallCount++;
          if (botsCallCount === 1) return pauseCheckChain;
          return botChain;
        }
        if (table === 'bot_building_presence') return presenceChain;
        if (table === 'chat_messages') {
          chatCallCount++;
          if (chatCallCount === 1) return recentMsgChain;
          return insertMsgChain;
        }
        if (table === 'events') return eventsChain;
        return createChainMock();
      }),
    } as never);
  }

  it('unwraps {"message":"Hello!"} into plain text for speak', async () => {
    setupSpeakMocks();

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"message":"Hello from JSON!"}',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(200);
    const data = await parseResponse<{ success: boolean }>(res);
    expect(data.success).toBe(true);
  });

  it('unwraps nested JSON with extra fields for speak', async () => {
    setupSpeakMocks();

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"message":"Hi","extra":"ignored"}',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(200);
  });

  it('rejects JSON with empty message field', async () => {
    setupSpeakMocks();

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"message":""}',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(400);
    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toBe('message required');
  });

  it('does not unwrap JSON without message field (treats as plain text)', async () => {
    setupSpeakMocks();

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"text":"Not a message field"}',
    });

    const res = await handleSimpleSpeak(req, env);
    // The raw JSON string is > 0 chars so it passes as a message (even if ugly)
    expect(res.status).toBe(200);
  });

  it('unwraps {"building_name":"Cafe"} for building enter', async () => {
    const req = new Request('https://api.test.com/buildings/enter', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"building_name":"The Byte Cafe"}',
    });

    const res = await handleSimpleBuildingEnter(req, env);
    expect(res.status).toBe(200);

    const calledRequest = vi.mocked(handleBuildingEnter).mock.calls[0][0] as Request;
    const calledBody = await calledRequest.json() as { building_name: string };
    expect(calledBody.building_name).toBe('The Byte Cafe');
  });

  it('unwraps {"name":"Cafe"} for building enter', async () => {
    const req = new Request('https://api.test.com/buildings/enter', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"name":"Pixel Atelier"}',
    });

    const res = await handleSimpleBuildingEnter(req, env);
    expect(res.status).toBe(200);

    const calledRequest = vi.mocked(handleBuildingEnter).mock.calls[0][0] as Request;
    const calledBody = await calledRequest.json() as { building_name: string };
    expect(calledBody.building_name).toBe('Pixel Atelier');
  });

  it('unwraps {"message":"Reply"} for owner reply', async () => {
    const req = new Request('https://api.test.com/owner-messages/reply', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"message":"Thanks human!"}',
    });

    const res = await handleSimpleOwnerReply(req, env);
    expect(res.status).toBe(200);

    const calledRequest = vi.mocked(handleOwnerMessageReply).mock.calls[0][0] as Request;
    const calledBody = await calledRequest.json() as { message: string };
    expect(calledBody.message).toBe('Thanks human!');
  });

  it('does not break creative text starting with {', async () => {
    setupSpeakMocks();

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: '{this is creative text, not JSON}',
    });

    const res = await handleSimpleSpeak(req, env);
    // Invalid JSON, so treated as plain text — should succeed
    expect(res.status).toBe(200);
  });

  it('handles non-string message field in JSON gracefully', async () => {
    setupSpeakMocks();

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer valid' },
      body: '{"message":12345}',
    });

    const res = await handleSimpleSpeak(req, env);
    // Non-string message field is not unwrapped, raw JSON becomes the message
    expect(res.status).toBe(200);
  });
});

