import { handleSimpleSpeak, handleSimpleMove, handleSimpleBuildingEnter, handleSimpleBuildingLeave, handleSimpleOwnerReply } from '../routes/simpleActions';
import { requireAuth } from '../middleware/auth';
import { createSupabaseClient } from '../lib/supabase';
import { checkRateLimit } from '../middleware/rateLimit';
import { handleBuildingEnter } from '../routes/buildings';
import { handleOwnerMessageReply } from '../routes/ownerMessages';

// ─── Shared setup ──────────────────────────────────────

const env = mockEnv();
const botPayload = mockJWTPayload({ sub: 'bot-1' });

function createChainMock(finalResult: { data?: unknown; error?: unknown; count?: number } = { data: null, error: null }) {
  const chain: Record<string, unknown> = {};
  const methods = ['select', 'eq', 'neq', 'is', 'in', 'or', 'order', 'limit', 'range', 'not', 'filter', 'gt', 'lt', 'gte', 'lte', 'overlaps'];
  for (const m of methods) {
    chain[m] = vi.fn().mockReturnValue(chain);
  }
  chain.single = vi.fn().mockResolvedValue(finalResult);
  chain.maybeSingle = vi.fn().mockResolvedValue(finalResult);
  chain.insert = vi.fn().mockReturnValue(chain);
  chain.upsert = vi.fn().mockReturnValue(chain);
  chain.update = vi.fn().mockReturnValue(chain);
  chain.delete = vi.fn().mockReturnValue(chain);
  chain.then = vi.fn((resolve: (v: unknown) => void) => resolve(finalResult));
  return chain;
}

// ─── Simple Speak — POST /world/speak ──────────────────

describe('Simple Speak — POST /world/speak', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(requireAuth).mockResolvedValue(botPayload);
    vi.mocked(checkRateLimit).mockResolvedValue({ allowed: true });
  });

  it('speaks with plain text body', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    const botChain = createChainMock({ data: { current_zone_id: 1, display_name: 'Test Bot', portrait_url: null }, error: null });
    const presenceChain = createChainMock({ data: null, error: null });
    const recentMsgChain = createChainMock({ data: [], error: null });
    const insertMsgChain = createChainMock({ data: { id: 'msg-1', ts: '2026-01-01T00:00:00Z' }, error: null });
    const eventsChain = createChainMock({ data: null, error: null });

    let botsCallCount = 0;
    let chatCallCount = 0;
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn((table: string) => {
        if (table === 'bots') {
          botsCallCount++;
          if (botsCallCount === 1) return pauseCheckChain;
          return botChain;
        }
        if (table === 'bot_building_presence') return presenceChain;
        if (table === 'chat_messages') {
          chatCallCount++;
          if (chatCallCount === 1) return recentMsgChain; // duplicate check
          return insertMsgChain; // insert
        }
        if (table === 'events') return eventsChain;
        return createChainMock();
      }),
    } as never);

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: 'Hello world!',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(200);

    const data = await parseResponse<{ success: boolean; message_id: string; session_id: string }>(res);
    expect(data.success).toBe(true);
    expect(data.message_id).toBe('msg-1');
    expect(data.session_id).toBe('zone_1');
  });

  it('rejects empty message', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: '',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(400);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toBe('message required');
  });

  it('rejects message over 500 chars', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: false }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const longMessage = 'a'.repeat(501);
    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: longMessage,
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(400);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toContain('max 500');
  });

  it('rejects paused bot', async () => {
    const pauseCheckChain = createChainMock({ data: { paused: true }, error: null });
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn(() => pauseCheckChain),
    } as never);

    const req = new Request('https://api.test.com/world/speak', {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain', 'Authorization': 'Bearer valid' },
      body: 'Hello!',
    });

    const res = await handleSimpleSpeak(req, env);
    expect(res.status).toBe(403);

    const data = await parseResponse<{ error: string }>(res);
    expect(data.error).toBe('bot_paused');
  });
});

