// Re-mock modules for heartbeat test section (heartbeat has its own Redis needs)
// Note: The vi.mock calls above are module-level, so they apply here too.
// We just need to import the heartbeat handler.

import { handleHeartbeat } from '../routes/heartbeat';
import { makeRequest } from './helpers';

describe('Heartbeat — Verification Reminder', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(requireAuth).mockResolvedValue(mockJWTPayload({ sub: 'bot-unverified-1', verified: false }));
    vi.mocked(checkRateLimit).mockResolvedValue({ allowed: true });
  });

  function setupVerificationMocks(opts: {
    verified: boolean;
    verificationCode?: string | null;
  }) {
    const { verified, verificationCode = 'OBC-TEST-1234' } = opts;

    // Cap check — existing active bot
    const capCheckChain = createChainMock({
      data: { last_seen_at: new Date(Date.now() - 10_000).toISOString(), status: 'online' },
      error: null,
    });

    // Bot zone + fields query
    const zoneChain = createChainMock({
      data: {
        current_zone_id: 1,
        display_name: 'UnverifiedBot',
        character_type: null,
        paused: false,
        skill_version: '2.0.47',
        verified,
      },
      error: null,
    });

    // Verification code lookup
    const verificationChain = createChainMock({
      data: verificationCode ? { code: verificationCode } : null,
      error: null,
    });

    // Other chains
    const updateChain = createChainMock({ data: null, error: null });
    const presenceChain = createChainMock({ data: null, error: null });
    const botPositionsChain = createChainMock({ data: [], error: null });
    const buildingsChain = createChainMock({ data: [], error: null });
    const messagesChain = createChainMock({ data: [], error: null });
    const zonesChain = createChainMock({ data: { id: 1, name: 'Zone 1', theme: 'urban' }, error: null });
    const reactionsChain = createChainMock({ data: [], error: null });
    const emptyChain = createChainMock({ data: [], error: null });

    let botsCallCount = 0;
    vi.mocked(createSupabaseClient).mockReturnValue({
      from: vi.fn((table: string) => {
        if (table === 'bots') {
          botsCallCount++;
          if (botsCallCount === 1) return capCheckChain;
          if (botsCallCount === 2) return zoneChain;
          return updateChain;
        }
        if (table === 'verification_codes') return verificationChain;
        if (table === 'bot_building_presence') return presenceChain;
        if (table === 'bot_positions') return botPositionsChain;
        if (table === 'buildings') return buildingsChain;
        if (table === 'chat_messages') return messagesChain;
        if (table === 'zones') return zonesChain;
        if (table === 'artifact_reactions') return reactionsChain;
        if (table === 'owner_messages') return emptyChain;
        if (table === 'dm_conversations') return emptyChain;
        if (table === 'dm_messages') return createChainMock({ data: [], error: null, count: 0 });
        if (table === 'proposals') return emptyChain;
        if (table === 'events') return updateChain;
        return createChainMock();
      }),
    } as never);
  }

  it('includes verification_needed in needs_attention for unverified bot', async () => {
    setupVerificationMocks({ verified: false, verificationCode: 'OBC-TEST-1234' });

    const req = makeRequest('/world/heartbeat', { token: 'valid' });
    const res = await handleHeartbeat(req, env);
    expect(res.status).toBe(200);

    const data = await parseResponse<{
      needs_attention?: { type: string; message?: string }[];
    }>(res);

    expect(data.needs_attention).toBeDefined();
    const verificationItem = data.needs_attention!.find(item => item.type === 'verification_needed');
    expect(verificationItem).toBeDefined();
    expect(verificationItem!.message).toContain('OBC-TEST-1234');
    expect(verificationItem!.message).toContain('openbotcity.com/verify');
  });

  it('no verification reminder for verified bot', async () => {
    setupVerificationMocks({ verified: true });
    vi.mocked(requireAuth).mockResolvedValue(mockJWTPayload({ sub: 'bot-verified-1', verified: true }));

    const req = makeRequest('/world/heartbeat', { token: 'valid' });
    const res = await handleHeartbeat(req, env);
    expect(res.status).toBe(200);

    const data = await parseResponse<{
      needs_attention?: { type: string; message?: string }[];
    }>(res);

    // Either needs_attention is undefined or it does not contain verification_needed
    if (data.needs_attention) {
      const verificationItem = data.needs_attention.find(item => item.type === 'verification_needed');
      expect(verificationItem).toBeUndefined();
    }
  });
});

